        <i className="fas fa-chevron-left"></i>
      </button>

      {/* Right Arrow */}
      <button 
        onClick={nextSlide}
        className="absolute right-4 top-1/2 -translate-y-1/2 bg-black/30 hover:bg-brand-primary hover:text-white text-white w-14 h-14 rounded-full backdrop-blur-md border border-white/10 flex items-center justify-center transition-all duration-300 z-30 opacity-0 group-hover:opacity-100 transform translate-x-4 group-hover:translate-x-0 shadow-lg"
